1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life", () => {
5	  it("should return empty grid for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty grid for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty grid for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep still life block unchanged", () => {
15	    expect(nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]])).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
16	  });
17	  it.todo("should kill live cell with more than 3 neighbors (overpopulation)");
18	  it.todo("should revive dead cell with exactly 3 live neighbors (reproduction)");
19	  it.todo("should transform blinker from vertical to horizontal");
